20	const calculatePolicyBase = (items: Item[]): number => {
21	  if (items.length === 3 && items.every((i) => i.type === items[0].type)) {
22	    return COMPONENT_BLOCK_BASE;
23	  }
24	  return items.reduce((sum, item) => sum + ITEM_BASE[item.type], 0);
25	};
26	
27	const quotePremium = ({ items }: Step): number => {
28	  const policyBase = calculatePolicyBase(items);
29	  const firstContractSurcharge = policyBase * FIRST_CONTRACT_SURCHARGE_RATE;
30	  return policyBase + firstContractSurcharge + PROCESSING_FEE;
31	};
32	
33	export const runScenario = ({ steps }: Scenario): { results: unknown[] } => {
34	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
35	  return { results };
